// Verantwortlichen pro Task ermitteln
const resp=(t)=>{
  // 1. V:-Tag
  const vTag=(t.tags||[]).find(tg=>tg.name&&tg.name.startsWith('v:'));
  if(vTag){return', V: '+vTag.name.substring(2);}
  // 2. Assignees
  const a=(t.assignees||[]);
