  const e=i.json;
  const start=e.start?.dateTime||e.start?.date||'';
  const end=e.end?.dateTime||e.end?.date||'';
  const d=start?new Date(start):null;
  const dStr=d?d.toLocaleDateString('de-DE',{day:'2-digit',month:'2-digit',year:'2-digit',timeZone:'Europe/Berlin'}):'';
  const tStr=d&&e.start?.dateTime?d.toLocaleTimeString('de-DE',{hour:'2-digit',minute:'2-digit',timeZone:'Europe/Berlin'}):'';
  return{summary:e.summary||'',date:dStr,time:tStr,ts:d?d.getTime():0};
}).sort((a,b)=>a.ts-b.ts);

// Group tasks by project
