  const cLines=comments.map(c=>{
    const d=c.date?new Date(parseInt(c.date)).toLocaleDateString('de-DE',{day:'2-digit',month:'2-digit'}):'?';
    let txt='';
    if(c.comment_text)txt=c.comment_text;
    else if(c.comment&&Array.isArray(c.comment))txt=c.comment.map(p=>p.text||'').join(' ');
    return'['+d+'] '+txt.substring(0,250);
  }).join('\n');
  sections.push('LETZTE GESPRÄCHSNOTIZEN ('+comments.length+'):\n'+cLines);
}

// 3. Kalender
if(calEvents.length>0){
