}

// 3. Per project
let totalOpen=0;let totalOverdue=0;let totalNoDate=0;
for(const[pid,proj]of Object.entries(projects)){
  const pt=proj.tasks;
  const overdue=pt.filter(t=>t.due_date&&parseInt(t.due_date)<now&&t.status?.type!=='closed'&&t.status?.type!=='done');
  const openDate=pt.filter(t=>t.due_date&&parseInt(t.due_date)>=now&&t.status?.type!=='closed'&&t.status?.type!=='done');
  const openNoDate=pt.filter(t=>!t.due_date&&t.status?.type!=='closed'&&t.status?.type!=='done');
  const closed=pt.filter(t=>(t.status?.type==='closed'||t.status?.type==='done')&&t.date_done&&parseInt(t.date_done)>twoWeeksAgo);
  totalOpen+=overdue.length+openDate.length+openNoDate.length;
  totalOverdue+=overdue.length;
  totalNoDate+=openNoDate.length;
  let s='PROJEKT: '+proj.name+'\n';
  if(overdue.length>0)s+='  ÜBERFÄLLIG:\n'+overdue.map(t=>'    - '+t.name+' (fällig: '+fD(t.due_date)+', Status: '+(t.status?.status||'?')+resp(t)+')').join('\n')+'\n';
  if(openDate.length>0)s+='  OFFEN (mit Datum):\n'+openDate.map(t=>'    - '+t.name+' (fällig: '+fD(t.due_date)+', Status: '+(t.status?.status||'?')+resp(t)+')').join('\n')+'\n';
