const https=require('https');const BOT='8689767896:AAEXRE7mifJ8ZpfgrGEp715-KYErH-t_HQU';const tg=(b)=>new Promise((res,rej)=>{const d=JSON.stringify(b);const r=https.request({hostname:'api.telegram.org',path:'/bot'+BOT+'/sendMessage',method:'POST',headers:{'Content-Type':'application/json','Content-Length':Buffer.byteLength(d)}},(_r)=>{let s='';_r.on('data',c=>s+=c);_r.on('end',()=>res(JSON.parse(s)));});r.on('error',rej);r.write(d);r.end();});

try {
const cb=$('Callback parsen').first().json;
const CID=parseInt(cb.chatId);
const msg=$('Admin: Router').first().json.msg||'\u2705 Erledigt.';

const ld=$getWorkflowStaticData('global');
const SPACE_MAP={'BEZ':'901510369336','INVANOVA':'901510374256','ACS':'901510378642','KuK':'901510427614','Persoenlich':'901510433640'};
const tasks=$('Admin: Reload').first().json.tasks||[];
const users={};
for(const t of tasks){
  const desc=(t.text_content||t.description||'');
  const lines=desc.split('\n').map(l=>l.trim()).filter(Boolean);
  const cfg={name:t.name,role:'user',perms:{},briefing:[],tgCid:''};
  for(const line of lines){
    const [key,...rest]=line.split(':');const val=rest.join(':').trim();
    if(key==='TG')cfg.tgCid=val;
    if(key==='Rolle')cfg.role=val.toLowerCase();
    if(key==='Briefing')cfg.briefing=val.split(',').map(Number).filter(Boolean);
    if(key==='Space'){const parts=val.split(':');const spaceName=parts[0];const perm=parts[1]||'r';const spaceId=SPACE_MAP[spaceName]||spaceName;cfg.perms['s:'+spaceId]=perm;}
  }
  if(cfg.role==='admin')cfg.perms={'*':'rwed'};
  if(cfg.tgCid)users[cfg.tgCid]=cfg;
}
if(Object.keys(users).length>0)ld.botUsers=users;

await tg({chat_id:CID,text:msg,reply_markup:{inline_keyboard:[[{text:'\u2699\ufe0f Admin',callback_data:JSON.stringify({st:'ad'})},{text:'\ud83c\udfe0 \u00dcbersicht',callback_data:JSON.stringify({st:'ma'})}]]}});
return [{json:{sent:true}}];
} catch(err) {
  try{const _c=parseInt($('Callback parsen').first().json.chatId)||0;if(_c)await tg({chat_id:_c,text:'\u26a0\ufe0f Fehler: '+(err.message||'').substring(0,100)});}catch(e2){}
  return [{json:{sent:false}}];
}
